adjusted_data AS (
        select
                TRY_CAST(`TYPE` AS STRING) AS `TYPE`,
                TRY_CAST(CODE AS INTEGER) AS CODE,
                TRY_CAST(DEBIT_CREDIT AS STRING) AS DEBIT_CREDIT,
                TRY_CAST(AFFECT AS STRING) AS AFFECT,
                TRY_CAST(`DESCRIPTION` AS STRING) AS `DESCRIPTION`,
                TRY_CAST(TRANSACTION_TYPE AS STRING) AS TRANSACTION_TYPE,
                TRY_CAST(ACCOUNT_TYPE AS STRING) AS ACCOUNT_TYPE,
                TRY_CAST(DESCRIPTION_CODE AS STRING) AS DESCRIPTION_CODE,
                TRY_CAST(TREATMENT_CODE AS STRING) AS TREATMENT_CODE
        FROM
                landing_data
)
SELECT *, current_timestamp() AS LOADED_AT FROM adjusted_data;
